+    use super::*;
+
+    // -----------------------------------------------------------------------
+    // Mock PageSymbolSink / PageSymbolSource
+    // -----------------------------------------------------------------------
+
+    struct VecPageSink {
+        symbols: BTreeMap<u32, Vec<u8>>,
+        flushed: bool,
+    }
+
+    impl VecPageSink {
