+    #[derive(Debug)]
+    struct VecTransportStream {
+        q: VecDeque<AuthenticatedSymbol>,
+    }
+
+    impl VecTransportStream {
+        fn new(symbols: Vec<Symbol>) -> Self {
+            let q = symbols
+                .into_iter()
+                .map(|s| AuthenticatedSymbol::new_verified(s, AuthenticationTag::zero()))
+                .collect();
