+    impl SymbolStream for VecTransportStream {
+        fn poll_next(
+            mut self: Pin<&mut Self>,
+            _cx: &mut Context<'_>,
+        ) -> Poll<Option<std::result::Result<AuthenticatedSymbol, StreamError>>> {
+            match self.q.pop_front() {
